sql:
SELECT name, sex
FROM passengers
WHERE embarked IN ('C', 'S');

SELECT 
  (SELECT COUNT(passenger_id) FROM passengers) AS total_passengers,
  (SELECT COUNT(crew_id) FROM crew_members) AS total_crew;

SELECT COUNT(DISTINCT passenger_id) AS num_passengers
FROM passenger_attributes
WHERE has_family_member_died = 1 AND pclass_1 = 1;

SELECT COUNT(passenger_id) 
FROM passengers 
WHERE embarked = 'C';

external_knowledge:
- "Night" is assumed as a launch time of 12:00 for the purposes of this query; 
- The terms "survived" and "did not survive" refer to whether a passenger survived the event being studied; 
- The terms "first-class" and "third-class" refer to the class of service the passenger was in, a measure of the luxury and cost of their accommodations.
